+import { afterEach, describe, expect, it, vi } from "vitest";
+import { createFetch } from "../src/base.ts";
+
+const response = (status: number, body = "") => new Response(body, { status });
+const options = { threshold: 1, cooldown: 100, failureStatusCodes: [503] };
+
+describe("circuit breaker", () => {
+  afterEach(() => {
+    vi.restoreAllMocks();
+  });
+
+  it("opens per origin and shares state with derived clients", async () => {
+    const fetch = vi.fn(async () => response(503));
+    const client = createFetch({ fetch });
+    const derived = client.create({});
+
+    await expect(
+      client("https://api.example.test/one", { circuitBreaker: options, retry: false })
+    ).rejects.toThrow();
+    await expect(
+      derived("https://api.example.test/two", { circuitBreaker: options })
+    ).rejects.toThrow("Circuit breaker is open");
+    expect(fetch).toHaveBeenCalledTimes(1);
+  });
+
+  it("keys requests after onRequest rewriting", async () => {
+    const fetch = vi.fn(async () => response(503));
+    const client = createFetch({ fetch });
+    const rewrite = (context: { request: string | URL | Request }) => {
+      context.request = "https://rewritten.example.test/resource";
+    };
+
+    await expect(
+      client("https://original.example.test/resource", {
+        circuitBreaker: options,
+        retry: false,
+        onRequest: rewrite,
+      })
+    ).rejects.toThrow();
+    await expect(
+      client("https://rewritten.example.test/other", {
+        circuitBreaker: options,
+      })
+    ).rejects.toThrow("Circuit breaker is open");
+    expect(fetch).toHaveBeenCalledTimes(1);
+  });
+
+  it("uses cooldown half-open probes and closes after a successful probe", async () => {
+    const now = vi.spyOn(Date, "now");
+    now.mockReturnValue(0);
+    const fetch = vi
+      .fn<() => Promise<Response>>()
+      .mockResolvedValueOnce(response(503))
+      .mockResolvedValueOnce(response(200, '"ok"'));
+    const client = createFetch({ fetch });
+
+    await expect(
+      client("https://api.example.test", { circuitBreaker: options, retry: false })
+    ).rejects.toThrow();
+    await expect(
+      client("https://api.example.test", { circuitBreaker: options })
+    ).rejects.toThrow("Circuit breaker is open");
+
+    now.mockReturnValue(100);
+    await expect(
+      client("https://api.example.test", { circuitBreaker: options })
+    ).resolves.toBe("ok");
+    expect(fetch).toHaveBeenCalledTimes(2);
+  });
+
+  it("limits concurrent half-open probes", async () => {
+    const now = vi.spyOn(Date, "now");
+    now.mockReturnValue(0);
+    let resolveProbe!: (value: Response) => void;
+    const fetch = vi
+      .fn<() => Promise<Response>>()
+      .mockResolvedValueOnce(response(503))
+      .mockImplementationOnce(
+        () => new Promise<Response>((resolve) => (resolveProbe = resolve))
+      );
+    const client = createFetch({ fetch });
+
+    await expect(
+      client("https://api.example.test", { circuitBreaker: options, retry: false })
+    ).rejects.toThrow();
+    now.mockReturnValue(100);
+    const probe = client("https://api.example.test", { circuitBreaker: options });
+    await expect(
+      client("https://api.example.test", { circuitBreaker: options })
+    ).rejects.toThrow("Circuit breaker is open");
+    resolveProbe(response(200, '"ok"'));
+    await expect(probe).resolves.toBe("ok");
